Вот простой пример SMTP-клиента на языке C с использованием библиотеки sockets. Этот пример подключается к SMTP-серверу, отправляет основное письмо, а затем закрывает соединение:

```c
#include <arpa/inet.h>
#include <netinet/in.h>
#include <stdbool.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/socket.h>
#include <unistd.h>

#define SMTP_SERVER "smtp.example.com"
#define SMTP_PORT 25
#define BUFFER_SIZE 1024

bool send_command(int sockfd, const char *command, const char *expected_response);
bool read_response(int sockfd, char *buffer, const char *expected_response);

int main() {
    int sockfd;
    struct sockaddr_in server_addr;
    char buffer[BUFFER_SIZE];

    // Create a socket
    if ((sockfd = socket(AF_INET, SOCK_STREAM, 0)) < 0) {
        perror("Socket creation failed");
        exit(EXIT_FAILURE);
    }

    // Set up server address
    memset(&server_addr, 0, sizeof(server_addr));
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(SMTP_PORT);
    if (inet_pton(AF_INET, SMTP_SERVER, &server_addr.sin_addr) <= 0) {
        perror("Invalid address");
        exit(EXIT_FAILURE);
    }

    // Connect to the SMTP server
    if (connect(sockfd, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        perror("Connection failed");
        exit(EXIT_FAILURE);
    }

    // Read server response
    if (!read_response(sockfd, buffer, "220")) {
        fprintf(stderr, "Failed to receive greeting from server\n");
        exit(EXIT_FAILURE);
    }

    // Send HELO command
    if (!send_command(sockfd, "HELO client.example.com\r\n", "250")) {
        fprintf(stderr, "Failed to send HELO command\n");
        exit(EXIT_FAILURE);
    }

    // Send MAIL FROM command
    if (!send_command(sockfd, "MAIL FROM:<sender@example.com>\r\n", "250")) {
        fprintf(stderr, "Failed to send MAIL FROM command\n");
        exit(EXIT_FAILURE);
    }

    // Send RCPT TO command
    if (!send_command(sockfd, "RCPT TO:<recipient@example.com>\r\n", "250")) {
        fprintf(stderr, "Failed to send RCPT TO command\n");
        exit(EXIT_FAILURE);
    }

    // Send DATA command
    if (!send_command(sockfd, "DATA\r\n", "354")) {
        fprintf(stderr, "Failed to send DATA command\n");
        exit(EXIT_FAILURE);
    }

    // Send email content
    const char *email_body =
        "Subject: Test Email\r\n"
        "\r\n"
        "Hello,\r\n"
        "\r\n"
        "This is a test email sent using C and sockets.\r\n"
        "\r\n"
        "Best Regards,\r\n"
        "Your Name\r\n"
        ".\r\n";

    if (!send_command(sockfd, email_body, "250")) {
        fprintf(stderr, "Failed to send email content\n");
        exit(EXIT_FAILURE);
    }

    // Send QUIT command
    if (!send_command(sockfd, "QUIT\r\n", "221")) {
        fprintf(stderr, "Failed to send QUIT command\n");
        exit(EXIT_FAILURE);
    }

    // Close the socket
    close(sockfd);
    printf("Email sent successfully\n");
    return 0;
}

bool send_command(int sockfd, const char *command, const char *expected_response) {
    send(sockfd, command, strlen(command), 0);
    char buffer[BUFFER_SIZE];
    return read_response(sockfd, buffer, expected_response);
}

bool read_response(int sockfd, char *buffer, const char *expected_response) {
    memset(buffer, 0, BUFFER_SIZE);
    ssize_t n = recv(sockfd, buffer, BUFFER_SIZE - 1, 0);
    if (n <= 0) {
        perror("Receive failed");
        exit(EXIT_FAILURE);
    }
    buffer[n] = '\0';
    printf("Server response: %s", buffer);
    return strncmp(buffer, expected_response, strlen(expected_response)) == 0;
}
```

Замените `SMTP_SERVER` на **домен** или **IP-адрес** вашего **SMTP-сервера** и обновите адреса **MAIL FROM** и **RCPT TO** на соответствующие адреса электронной почты. Также не забудьте обновить тему и текст письма, если это необходимо.

Обратите внимание, что данный пример использует соединение в виде обычного текста и не поддерживает аутентификацию или шифрование. Для реальных приложений используйте библиотеки типа `libcurl` или `libesmtp`, которые поддерживают безопасные соединения и аутентификацию.

SMTP (Simple Mail Transfer Protocol) - это протокол, используемый для отправки электронной почты через Интернет. Реализация SMTP на чистом C может включать в себя создание сокета для соединения с сервером SMTP, формирование и отправку сообщений с использованием команд SMTP и обработку ответов сервера. Вот пример кода, который демонстрирует отправку электронного письма с использованием SMTP на чистом C:

``` #include <stdio.h>
#include <string.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>
#include <unistd.h>

#define SMTP_PORT 25
#define MAXLINE 1024

int main(int argc, char **argv) {
    int sockfd;
    struct sockaddr_in servaddr;
    char sendline[MAXLINE], recvline[MAXLINE];

    if (argc != 2) {
        printf("Usage: %s <IP address>\n", argv[0]);
        return 1;
    }

    if ((sockfd = socket(AF_INET, SOCK_STREAM, 0)) < 0) {
        perror("socket error");
        return 1;
    }

    bzero(&servaddr, sizeof(servaddr));
    servaddr.sin_family = AF_INET;
    servaddr.sin_port = htons(SMTP_PORT);
    if (inet_pton(AF_INET, argv[1], &servaddr.sin_addr) <= 0) {
        perror("inet_pton error");
        return 1;
    }

    if (connect(sockfd, (struct sockaddr *) &servaddr, sizeof(servaddr)) < 0) {
        perror("connect error");
        return 1;
    }

    while (fgets(sendline, MAXLINE, stdin) != NULL) {
        write(sockfd, sendline, strlen(sendline));

        if (read(sockfd, recvline, MAXLINE) == 0) {
            perror("server terminated prematurely");
            return 1;
        }

        fputs(recvline, stdout);
    }

    close(sockfd);
    return 0;
}
```
